ConstructorArguments:
A networkable dictionary for use with the <span style="color: #4EC9B0;">SyncAttribute</span> and <span style="color: #4EC9B0;">HostSyncAttribute</span>. Only changes will be networked instead of sending the whole dictionary every time, so it's more efficient. <br></br><br/><b>Example usage:</b><pre style="color: #DCDCDC; background-color: #111111;"><code>
    public class MyComponent : Component
    {
    	[Sync] public NetDictionary&lt;string,bool&gt; MyBoolTable { get; set; } = new();

    	public void SetBoolState( string key, bool state )
    	{
    		if ( IsProxy ) return;
    		MyBoolTable[key] = state;
    	}
    }
    </code></pre><br/>

